/**
 * Diagnostic question top-up seed script.
 * Brings every course to exactly 30 diagnostic questions.
 * Run: node server/seed-diag-topup.mjs
 *
 * Actual diagnosticQuestions schema:
 *   id (int auto_increment PK), questionId (varchar 32 unique), questionText (text),
 *   questionType (enum: multiple_choice|short_answer), choices (json),
 *   correctAnswer (varchar 512), mapsToUnit (varchar 64), mapsToSkills (json NOT NULL),
 *   difficulty (enum: easy|medium), explanation (text), sortOrder (int), courseId (int)
 */
import { createConnection } from 'mysql2/promise';
import { config } from 'dotenv';
config();

const db = await createConnection(process.env.DATABASE_URL);

async function getCourseId(code) {
  const [[row]] = await db.execute('SELECT id FROM courses WHERE courseCode = ?', [code]);
  if (!row) throw new Error(`Course not found: ${code}`);
  return row.id;
}

async function countDiag(courseId) {
  const [[row]] = await db.execute('SELECT COUNT(*) as n FROM diagnosticQuestions WHERE courseId = ?', [courseId]);
  return Number(row.n);
}

async function getUnitTitles(courseId) {
  const [rows] = await db.execute('SELECT title FROM units WHERE courseId = ? ORDER BY unitNumber', [courseId]);
  return rows.map(r => r.title);
}

let sortCounter = 2000;

async function insertDiag(courseId, mapsToUnit, questionId, text, choices, correct, explanation, difficulty) {
  await db.execute(
    `INSERT IGNORE INTO diagnosticQuestions
     (questionId, questionText, questionType, choices, correctAnswer, mapsToUnit, mapsToSkills, difficulty, explanation, sortOrder, courseId)
     VALUES (?, ?, 'multiple_choice', ?, ?, ?, '[]', ?, ?, ?, ?)`,
    [questionId, text, JSON.stringify(choices), correct, mapsToUnit, difficulty, explanation, ++sortCounter, courseId]
  );
}

