// ─── main seeding logic ───────────────────────────────────────────────────────

const allCourses = [
  { code: 'APCHEM', questions: APCHEM_QUESTIONS },
  { code: 'APSTAT', questions: APSTAT_QUESTIONS },
  { code: 'APCALCBC', questions: APCALCBC_QUESTIONS },
  { code: 'APLIT', questions: APLIT_QUESTIONS },
  { code: 'APBIZ', questions: APBIZ_QUESTIONS },
  { code: 'SATPREP', questions: SATPREP_QUESTIONS },
  { code: 'ENG1', questions: ENG1_QUESTIONS },
  { code: 'BIO1', questions: BIO1_QUESTIONS },
  { code: 'APHG', questions: APHG_QUESTIONS },
  { code: 'SPA2', questions: SPA2_QUESTIONS },
  { code: 'GR3MATH', questions: GR3MATH_QUESTIONS },
  { code: 'GR3ELA', questions: GR3ELA_QUESTIONS },
  { code: 'GR3SCI', questions: GR3SCI_QUESTIONS },
  { code: 'GR3SS', questions: GR3SS_QUESTIONS },
];

for (const { code, questions } of allCourses) {
  const courseId = await getCourseId(code);
  const unitTitles = await getUnitTitles(courseId);
  const current = await countDiag(courseId);
  console.log(`${code}: currently ${current} questions, adding ${questions.length}...`);

  for (let i = 0; i < questions.length; i++) {
    const [qId, text, choices, correct, explanation, difficulty] = questions[i];
    const mapsToUnit = unitTitles[i % unitTitles.length] || 'General';
    await insertDiag(courseId, mapsToUnit, qId, text, choices, correct, explanation, difficulty);
  }

  const after = await countDiag(courseId);
  console.log(`  -> ${code}: now ${after} questions`);
}

// Trim ALG1 to 30 (it has 57)
const alg1Id = await getCourseId('ALG1');
const alg1Count = await countDiag(alg1Id);
if (alg1Count > 30) {
  console.log(`ALG1: trimming from ${alg1Count} to 30...`);
  await db.execute(`
    DELETE FROM diagnosticQuestions
    WHERE courseId = ?
    ORDER BY id DESC
    LIMIT ${alg1Count - 30}
  `, [alg1Id]);
  const after = await countDiag(alg1Id);
  console.log(`  -> ALG1: now ${after} questions`);
}

await db.end();
console.log('\nAll diagnostic question banks updated to 30 questions.');
